// TestCodeOrchWriteBody_MarshalsToJSONObject pins the write-body contract.
//
// Regression context: handleCodeOrchExecute once pre-marshaled params to
// []byte and passed that []byte to client.{Post,Put,Patch}. client.do()
// marshals the body value exactly once. json.Marshal([]byte) emits a
// base64-encoded JSON string, so the API received a string where it expected
// the request object. GET/DELETE never carry a body, so the defect stayed
// latent until a write operation exercised the path.
//
// The orchestrator must hand the client the structured params map, never
// pre-marshaled bytes.
func TestCodeOrchWriteBody_MarshalsToJSONObject(t *testing.T) {
	params := map[string]any{
		"reference": "example-reference",
		"notes":     "structured write body",
		"type":      map[string]any{"id": "type-1"},
		"items": []any{
			map[string]any{"row": 1, "account": map[string]any{"id": "account-1"}, "amount": 234},
		},
	}

	// client.do() performs exactly one json.Marshal on the body value it is
	// handed. Model that here.
	wire, err := json.Marshal(codeOrchWriteBody(params))
	if err != nil {
		t.Fatalf("marshal write body: %v", err)
	}
	if len(wire) == 0 || wire[0] != '{' {
		t.Fatalf("write body must be a JSON object the API can map; got: %s", wire)
	}
	var rt map[string]any
	if err := json.Unmarshal(wire, &rt); err != nil {
		t.Fatalf("API would 422 this: body is not a mappable object: %v; wire=%s", err, wire)
	}
	if rt["reference"] != "example-reference" || rt["notes"] != "structured write body" {
		t.Fatalf("fields lost through write-body path: %#v", rt)
	}

	// Guard against reintroduction: prove the OLD path (pre-marshal, then
	// client re-marshal) corrupts the body into a base64 JSON string.
	preMarshaled, _ := json.Marshal(params)  // what the buggy code passed as body
	doubled, _ := json.Marshal(preMarshaled) // what client.do() then produced on the wire
	if len(doubled) == 0 || doubled[0] != '"' {
		t.Fatalf("expected the double-marshal bug to yield a JSON string; got: %s", doubled)
	}
}

